const PREFIX="[Correctly]",LEVELS={debug:{rank:0,style:"color: #888"},info:{rank:1,style:"color: #2d7d46; font-weight: bold"},warn:{rank:2,style:"color: #e65100; font-weight: bold"},error:{rank:3,style:"color: #c62828; font-weight: bold"},silent:{rank:4,style:""}};export const LOG_LEVELS=Object.keys(LEVELS);let currentRank=LEVELS.info.rank;function loadLogLevel(){typeof chrome<"u"&&chrome.storage?.local&&chrome.storage.local.get("logLevel").then(({logLevel})=>{setLogLevel(logLevel||"info")}).catch(()=>{})}function listenForChanges(){typeof chrome<"u"&&chrome.storage?.onChanged&&chrome.storage.onChanged.addListener(changes=>{changes.logLevel&&setLogLevel(changes.logLevel.newValue||"info")})}export function setLogLevel(level){const entry=LEVELS[level];entry&&(currentRank=entry.rank)}loadLogLevel(),listenForChanges();function shouldLog(level){return LEVELS[level].rank>=currentRank}export function createLogger(tag){const tagStr=`${PREFIX}[${tag}]`;return{debug:(...args)=>{shouldLog("debug")&&console.debug(`%c${tagStr}`,LEVELS.debug.style,...args)},info:(...args)=>{shouldLog("info")&&console.info(`%c${tagStr}`,LEVELS.info.style,...args)},warn:(...args)=>{shouldLog("warn")&&console.warn(`%c${tagStr}`,LEVELS.warn.style,...args)},error:(...args)=>{shouldLog("error")&&console.error(`%c${tagStr}`,LEVELS.error.style,...args)},time:label=>{if(!shouldLog("debug"))return()=>{};const key=`${tagStr} ${label}#${Date.now()}`;return console.time(key),()=>console.timeEnd(key)},group:(label,fn)=>{if(!shouldLog("info")){fn();return}console.groupCollapsed(`%c${tagStr} ${label}`,LEVELS.info.style);try{fn()}finally{console.groupEnd()}},table:data=>{shouldLog("debug")&&console.table(data)}}}
